 83   }
 84   // Type inference not implemented for opcode.
 85   LLVM_DEBUG({
 86     dbgs() << "LV: Found unhandled opcode for: ";
 87     R->getVPSingleValue()->dump();
 88   });
 89   llvm_unreachable("Unhandled opcode!");
