1022         "Must not overlap with the metadata bit");
1023     return Bitfield::get<BitfieldElement>(getSubclassDataFromValue());
1024   }
1025 
1026   template <typename BitfieldElement>
1027   void setSubclassData(typename BitfieldElement::Type Value) {
1028     static_assert(
1029         std::is_same<BitfieldElement, HasMetadataField>::value ||
1030             !Bitfield::isOverlapping<BitfieldElement, HasMetadataField>(),
1031         "Must not overlap with the metadata bit");
1032     auto Storage = getSubclassDataFromValue();
1033     Bitfield::set<BitfieldElement>(Storage, Value);
1034     setValueSubclassData(Storage);
1035   }
1036 
1037   Instruction(Type *Ty, unsigned iType, AllocInfo AllocInfo,
1038               InsertPosition InsertBefore = nullptr);
